import{_ as e,C as p,o as l,c as i,j as s,a as r,E as t,ag as c}from"./chunks/framework.CAXxHpAX.js";const v=JSON.parse('{"title":"12. 数据湖与湖仓架构","description":"用对象存储、文件格式、表格式、Catalog 和多引擎查询构建开放分析底座。","frontmatter":{"title":"12. 数据湖与湖仓架构","description":"用对象存储、文件格式、表格式、Catalog 和多引擎查询构建开放分析底座。","prev":{"text":"11. 图数据库：面向关系网络 / 知识图谱 / 路径分析的数据系统","link":"/chapters/11-graph-databases"},"next":{"text":"13. 数据治理与工程化","link":"/chapters/13-data-governance"}},"headers":[],"relativePath":"chapters/12-lakehouse.md","filePath":"chapters/12-lakehouse.md"}'),o={name:"chapters/12-lakehouse.md"};function b(u,a,d,h,g,m){const n=p("Mermaid");return l(),i("div",null,[a[0]||(a[0]=s("h1",{id:"_12-数据湖与湖仓架构",tabindex:"-1"},[r("12. 数据湖与湖仓架构 "),s("a",{class:"header-anchor",href:"#_12-数据湖与湖仓架构","aria-label":'Permalink to "12. 数据湖与湖仓架构"'},"​")],-1)),a[1]||(a[1]=s("div",{class:"tip custom-block"},[s("p",{class:"custom-block-title"},"本章导读"),s("p",null,"用对象存储、文件格式、表格式、Catalog 和多引擎查询构建开放分析底座。")],-1)),t(n,{code:"flowchart%20LR%0A%20%20DB%5B%22PostgreSQL%20%2F%20MySQL%22%5D%20--%3E%20I%5B%22Ingestion%22%5D%0A%20%20I%20--%3E%20O%5B%22Object%20Storage%22%5D%0A%20%20O%20--%3E%20P%5B%22Parquet%22%5D%0A%20%20P%20--%3E%20T%5B%22Iceberg%20%2F%20Delta%20%2F%20Hudi%22%5D%0A%20%20T%20--%3E%20S%5B%22Spark%22%5D%0A%20%20T%20--%3E%20TR%5B%22Trino%22%5D%0A%20%20T%20--%3E%20F%5B%22Flink%22%5D%0A%20%20TR%20--%3E%20BI%5B%22BI%20%2F%20AI%22%5D%0A"}),a[2]||(a[2]=c(`<p>数据湖解决低成本和灵活存储。</p><p>数仓解决高质量建模和稳定分析。</p><h2 id="问题切入" tabindex="-1">问题切入 <a class="header-anchor" href="#问题切入" aria-label="Permalink to &quot;问题切入&quot;">​</a></h2><p>湖仓试图统一两者：在开放存储上获得表管理、事务、元数据、演化和多引擎分析能力。</p><p>前面的章节已经出现了很多数据形态：PostgreSQL 业务表、数仓事实表、Kafka 事件、Parquet 文件、OLAP 宽表、RAG 文档、向量、图谱和评测日志。它们不可能全部只放在一个业务库或一个 OLAP 数据库里。</p><p>团队很快会遇到这些问题：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>历史明细太多，放在业务库成本和风险都太高。</span></span>
<span class="line"><span>日志、文档、图片、模型输入输出不是传统数仓表。</span></span>
<span class="line"><span>Spark、Flink、Trino、DuckDB 都希望访问同一批数据。</span></span>
<span class="line"><span>文件在对象存储里越来越多，但不知道哪份是最新、可用、可信版本。</span></span>
<span class="line"><span>schema 变化后，下游任务不知道该如何兼容。</span></span>
<span class="line"><span>AI 应用需要同时访问原文、分块、向量、图谱和评测数据。</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p>数据湖出现是为了承载开放、多样、低成本的数据存储；湖仓出现是为了避免数据湖失控成“数据沼泽”。</p><h2 id="核心判断" tabindex="-1">核心判断 <a class="header-anchor" href="#核心判断" aria-label="Permalink to &quot;核心判断&quot;">​</a></h2><blockquote><p>湖仓的关键不是“湖 + 仓”的口号，而是用表格式把对象存储中的文件组织成可管理、可查询、可演化的数据表。</p></blockquote><p>本章要建立的判断是：湖仓架构解决的是开放存储上的数据管理问题。它用文件格式、表格式、Catalog 和多引擎访问，把对象存储里的文件变成可治理、可演化、可查询的数据表。</p><p>湖仓也不是万能替代品。它不能自动完成业务建模，不能替代 OLAP 数据库的高并发低延迟服务能力，不能省掉质量、权限、血缘和指标治理。它提供的是长期开放数据底座。</p><h2 id="机制解释" tabindex="-1">机制解释 <a class="header-anchor" href="#机制解释" aria-label="Permalink to &quot;机制解释&quot;">​</a></h2><h3 id="_12-1-数据湖基础" tabindex="-1">12.1 数据湖基础 <a class="header-anchor" href="#_12-1-数据湖基础" aria-label="Permalink to &quot;12.1 数据湖基础&quot;">​</a></h3><p>数据湖通常建立在对象存储上，例如 S3、OSS、MinIO。</p><p>它可以保存各种数据：</p><ul><li>CSV。</li><li>JSON。</li><li>日志。</li><li>图片。</li><li>音频。</li><li>文档。</li><li>Parquet。</li><li>ORC。</li><li>模型输入输出。</li><li>AI 中间产物。</li></ul><p>数据湖的优势是低成本、开放和灵活。</p><p>但如果缺乏管理，数据湖会变成数据沼泽：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>文件命名混乱</span></span>
<span class="line"><span>目录含义不清</span></span>
<span class="line"><span>schema 不可追踪</span></span>
<span class="line"><span>质量不可验证</span></span>
<span class="line"><span>权限不可控制</span></span>
<span class="line"><span>血缘不可解释</span></span>
<span class="line"><span>下游不知道该用哪份数据</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><p>所以数据湖需要元数据、目录、质量、权限和表格式。</p><h3 id="_12-2-文件格式" tabindex="-1">12.2 文件格式 <a class="header-anchor" href="#_12-2-文件格式" aria-label="Permalink to &quot;12.2 文件格式&quot;">​</a></h3><p>常见文件格式包括：</p><ul><li>CSV。</li><li>JSON。</li><li>Avro。</li><li>Parquet。</li><li>ORC。</li></ul><p>CSV 简单但缺乏类型信息，压缩和列裁剪能力弱。</p><p>JSON 灵活，适合半结构化数据，但分析扫描成本高。</p><p>Avro 适合行式序列化和 schema 演化。</p><p>Parquet 和 ORC 是列式存储格式，适合分析。</p><p>Parquet 的价值在于：</p><ul><li>列式读取。</li><li>压缩效率高。</li><li>支持嵌套结构。</li><li>适合 Spark、Trino、DuckDB 等引擎查询。</li></ul><p>文件格式解决的是“数据如何物理存储”。</p><p>但它不解决事务、并发写入、快照、表演化和元数据管理。</p><p>这就是表格式出现的原因。</p><h3 id="_12-3-表格式" tabindex="-1">12.3 表格式 <a class="header-anchor" href="#_12-3-表格式" aria-label="Permalink to &quot;12.3 表格式&quot;">​</a></h3><p>现代湖仓常见表格式包括：</p><ul><li>Apache Iceberg。</li><li>Delta Lake。</li><li>Apache Hudi。</li></ul><p>它们把对象存储上的文件组织成表，并提供：</p><ul><li>表元数据。</li><li>快照。</li><li>schema 演化。</li><li>分区演化。</li><li>ACID 能力。</li><li>时间旅行。</li><li>增量读取。</li><li>文件 compaction。</li></ul><p>Iceberg 的核心价值可以理解为：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Object Storage 上的文件</span></span>
<span class="line"><span>  -&gt; 通过元数据组织成表</span></span>
<span class="line"><span>  -&gt; 多引擎可查询</span></span>
<span class="line"><span>  -&gt; 支持快照和演化</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>表格式的核心判断是：</p><blockquote><p>表格式让数据湖里的文件具备类似数据库表的管理能力。</p></blockquote><h3 id="_12-4-查询引擎" tabindex="-1">12.4 查询引擎 <a class="header-anchor" href="#_12-4-查询引擎" aria-label="Permalink to &quot;12.4 查询引擎&quot;">​</a></h3><p>湖仓不是一个单一数据库，而是存储、表格式、Catalog 和查询引擎的组合。</p><p>常见查询引擎包括：</p><ul><li>Spark。</li><li>Flink。</li><li>Trino。</li><li>Presto。</li><li>Hive。</li><li>DuckDB。</li></ul><p>Spark 适合批处理和大规模转换。</p><p>Flink 适合流式写入和实时计算。</p><p>Trino 适合交互式 SQL 查询。</p><p>DuckDB 适合本地分析和文件探索。</p><p>同一份 Iceberg 表，可以被多个引擎访问，这就是开放表格式的价值。</p><h3 id="_12-5-catalog" tabindex="-1">12.5 Catalog <a class="header-anchor" href="#_12-5-catalog" aria-label="Permalink to &quot;12.5 Catalog&quot;">​</a></h3><p>Catalog 负责管理表元数据的位置和命名空间。</p><p>常见 Catalog 包括：</p><ul><li>Hive Metastore。</li><li>AWS Glue Catalog。</li><li>Nessie。</li><li>Iceberg REST Catalog。</li><li>Unity Catalog。</li></ul><p>Catalog 解决的是：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>有哪些库？</span></span>
<span class="line"><span>有哪些表？</span></span>
<span class="line"><span>表的元数据在哪里？</span></span>
<span class="line"><span>表属于哪个命名空间？</span></span>
<span class="line"><span>谁能访问？</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>没有 Catalog，多引擎就很难稳定找到和理解同一张表。</p><h3 id="_12-6-湖仓典型架构" tabindex="-1">12.6 湖仓典型架构 <a class="header-anchor" href="#_12-6-湖仓典型架构" aria-label="Permalink to &quot;12.6 湖仓典型架构&quot;">​</a></h3><p>典型链路是：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>PostgreSQL / MySQL</span></span>
<span class="line"><span>  -&gt; CDC / Batch Ingestion</span></span>
<span class="line"><span>  -&gt; Object Storage</span></span>
<span class="line"><span>  -&gt; Parquet</span></span>
<span class="line"><span>  -&gt; Iceberg / Delta / Hudi</span></span>
<span class="line"><span>  -&gt; Spark / Flink / Trino</span></span>
<span class="line"><span>  -&gt; dbt</span></span>
<span class="line"><span>  -&gt; BI / AI / ML</span></span>
<span class="line"><span>  -&gt; 向量数据库 / 图数据库</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div><p>在这条链路中：</p><ul><li>PostgreSQL 提供业务事实。</li><li>CDC / Batch 负责写入湖仓。</li><li>Object Storage 保存数据文件。</li><li>Parquet 提供列式分析格式。</li><li>Iceberg / Delta / Hudi 提供表管理。</li><li>Spark / Flink / Trino 提供计算和查询。</li><li>BI / AI / ML 使用结果。</li></ul><h2 id="系统位置" tabindex="-1">系统位置 <a class="header-anchor" href="#系统位置" aria-label="Permalink to &quot;系统位置&quot;">​</a></h2><p>湖仓是现代数据平台的开放数据底座。</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>业务库 / 日志 / 文件 / 文档 / 模型产物</span></span>
<span class="line"><span>  -&gt; Ingestion</span></span>
<span class="line"><span>  -&gt; Object Storage</span></span>
<span class="line"><span>  -&gt; Parquet / ORC</span></span>
<span class="line"><span>  -&gt; Iceberg / Delta / Hudi</span></span>
<span class="line"><span>  -&gt; Catalog</span></span>
<span class="line"><span>  -&gt; Spark / Flink / Trino / DuckDB</span></span>
<span class="line"><span>  -&gt; 数仓 / OLAP / 向量库 / 图数据库 / AI 应用</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><p>它承接前面所有数据形态：批处理产物可以写入湖仓，实时流可以增量写入湖仓，向量和图谱的原始文档、中间结果和评测数据也可以沉淀在湖仓中。</p><p>它也引出第 13 章数据治理：一旦数据跨越业务库、数仓、湖仓、OLAP、向量和图，如果没有质量、元数据、血缘、权限和指标治理，开放存储只会扩大混乱。</p><h2 id="场景案例" tabindex="-1">场景案例 <a class="header-anchor" href="#场景案例" aria-label="Permalink to &quot;场景案例&quot;">​</a></h2><p>一个 Mini Lakehouse 可以这样搭建：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>PostgreSQL orders / users / products</span></span>
<span class="line"><span>  -&gt; Airbyte 批量同步</span></span>
<span class="line"><span>  -&gt; MinIO 对象存储</span></span>
<span class="line"><span>  -&gt; Parquet 文件</span></span>
<span class="line"><span>  -&gt; Iceberg 表</span></span>
<span class="line"><span>  -&gt; Spark 做批量转换</span></span>
<span class="line"><span>  -&gt; Trino 做交互式查询</span></span>
<span class="line"><span>  -&gt; DuckDB 做本地抽样分析</span></span>
<span class="line"><span>  -&gt; RAG 文档和评测日志也沉淀到对象存储</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div><p>数据目录可以按层组织：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>lake/</span></span>
<span class="line"><span>  raw/           原始文件和同步落地数据</span></span>
<span class="line"><span>  bronze/        基础清洗表</span></span>
<span class="line"><span>  silver/        标准明细表</span></span>
<span class="line"><span>  gold/          汇总和应用表</span></span>
<span class="line"><span>  ai/            文档、chunk、embedding 版本、评测数据</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p>这个案例里，Parquet 负责列式文件存储，Iceberg 负责把文件组织成表，Catalog 负责让 Spark 和 Trino 找到同一张表，Spark 负责批量转换，Trino 负责交互查询。</p><p>湖仓的价值不是让所有查询都最快，而是让数据长期开放、可管理、可被多种计算引擎复用。</p><h2 id="常见误区" tabindex="-1">常见误区 <a class="header-anchor" href="#常见误区" aria-label="Permalink to &quot;常见误区&quot;">​</a></h2><p><strong>误区一：数据湖就是便宜存储。</strong></p><p>只有存储没有管理，数据湖会变成数据沼泽。</p><p><strong>误区二：Parquet 等于湖仓。</strong></p><p>Parquet 是文件格式，不是表格式。湖仓还需要快照、元数据、事务、演化和 Catalog。</p><p><strong>误区三：湖仓可以替代所有 OLAP 数据库。</strong></p><p>湖仓适合开放存储和多引擎数据管理，高并发低延迟 BI 仍可能需要 ClickHouse、Doris 等 OLAP 服务层。</p><p><strong>误区四：有 Parquet 文件就等于有表。</strong></p><p>文件格式只解决物理存储，不解决快照、并发、事务、schema 演化、分区演化和多引擎一致访问。</p><p><strong>误区五：湖仓可以不用数仓建模。</strong></p><p>湖仓提供存储和表管理能力，但事实表、维度表、指标口径和数据分层仍然需要设计。没有建模的湖仓仍然会变成数据沼泽。</p><h2 id="实战任务" tabindex="-1">实战任务 <a class="header-anchor" href="#实战任务" aria-label="Permalink to &quot;实战任务&quot;">​</a></h2><p>设计一个 Mini Lakehouse：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>PostgreSQL</span></span>
<span class="line"><span>  -&gt; Airbyte</span></span>
<span class="line"><span>  -&gt; MinIO</span></span>
<span class="line"><span>  -&gt; Parquet</span></span>
<span class="line"><span>  -&gt; Iceberg</span></span>
<span class="line"><span>  -&gt; Trino / Spark</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p>要求说明：</p><ul><li>哪些表同步进湖仓。</li><li>文件格式选择。</li><li>表格式选择。</li><li>Catalog 选择。</li><li>分区策略。</li><li>哪些任务用 Spark。</li><li>哪些查询用 Trino。</li><li>哪些数据进入向量库或图数据库。</li></ul><p>补充要求：</p><ul><li>为 <code>orders</code> 表设计 Iceberg 分区策略。</li><li>说明 schema 新增字段时如何兼容旧数据。</li><li>说明一次错误写入如何通过快照或回滚恢复。</li><li>设计一个 Catalog 命名空间，例如 <code>raw</code>、<code>silver</code>、<code>gold</code>、<code>ai</code>。</li><li>说明哪些高并发看板仍应同步到 ClickHouse 或 Doris。</li></ul><h2 id="小结引出下一章" tabindex="-1">小结引出下一章 <a class="header-anchor" href="#小结引出下一章" aria-label="Permalink to &quot;小结引出下一章&quot;">​</a></h2><p>数据湖提供灵活开放存储，数仓提供建模和治理，湖仓用表格式尝试统一两者。</p><p>下一章进入数据治理。</p><p>因为数据平台一旦跨越 PostgreSQL、数仓、湖仓、向量和图，如果没有治理，就无法保证可信、可追踪、可复用和可控制。</p>`,97))])}const C=e(o,[["render",b]]);export{v as __pageData,C as default};
